import{_ as o,o as a,c as r,a2 as e}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"1972年 核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1972年/核心总结.md","filePath":"01_letters/1972年/核心总结.md"}'),d={name:"01_letters/1972年/核心总结.md"};function l(n,t,s,i,h,u){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_1972年-核心总结" tabindex="-1">1972年 核心总结 <a class="header-anchor" href="#_1972年-核心总结" aria-label="Permalink to &quot;1972年 核心总结&quot;">​</a></h1><blockquote><p><strong>一句话总结：</strong> 营业收益达到股东权益的 <strong>19.8%</strong>，创历史新高！三大收购（Jack Ringwalt、Gene Abegg、Vic Raab）全面开花，伯克希尔正式进入&quot;黄金时代&quot;。</p></blockquote><h2 id="核心数据" tabindex="-1">核心数据 <a class="header-anchor" href="#核心数据" aria-label="Permalink to &quot;核心数据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>1972年</th><th>历史对比</th></tr></thead><tbody><tr><td>营业收益</td><td><strong>1111.6万美元</strong></td><td>历史新高</td></tr><tr><td>ROE</td><td><strong>19.8%</strong></td><td>历史最高纪录</td></tr><tr><td>每股账面价值增长</td><td>年均复合 <strong>16.8%</strong></td><td>自1964年来</td></tr><tr><td>流通股数量</td><td><strong>减少14%</strong></td><td>持续回购</td></tr></tbody></table><h2 id="三位创始人-全面成功" tabindex="-1">&quot;三位创始人&quot;全面成功 <a class="header-anchor" href="#三位创始人-全面成功" aria-label="Permalink to &quot;&quot;三位创始人&quot;全面成功&quot;">​</a></h2><p>1972年的年报，是巴菲特第一次系统性地称赞三位被他收购子公司的创始人：</p><blockquote><p>&quot;三位公司的创始人都是主要出售方，获得了大额现金对价，但仍以不减的热情与创造力继续经营，推动业绩再创新高。&quot;</p></blockquote><ul><li><strong>Jack Ringwalt</strong>：国民赔偿保险，承保利润历史最高</li><li><strong>Gene Abegg</strong>：伊利诺伊国民银行，持续跑赢全行业</li><li><strong>Vic Raab</strong>：家庭与汽车保险公司，1972年继续优异表现</li></ul><p>三人都是&quot;现金出售后仍全职投入&quot;的类型。这在未来成为伯克希尔收购文化的核心模板。</p><h2 id="业务板块详解" tabindex="-1">业务板块详解 <a class="header-anchor" href="#业务板块详解" aria-label="Permalink to &quot;业务板块详解&quot;">​</a></h2><h3 id="保险-超高利润-但危机潜伏" tabindex="-1">保险：超高利润，但危机潜伏 <a class="header-anchor" href="#保险-超高利润-但危机潜伏" aria-label="Permalink to &quot;保险：超高利润，但危机潜伏&quot;">​</a></h3><p>1972年，国民赔偿保险的核心业务取得了&quot;超高承保利润&quot;。但巴菲特在欣喜之余写下了关键警告：</p><blockquote><p>&quot;如果今年利润没有如此暴涨，我们未来五年的前景或许会更好。&quot;</p></blockquote><p>原因：超高利润吸引了大量新竞争者，以不具备合理补偿性的低费率进入市场。这会在未来1-2年内严重损害行业盈利能力。</p><p>这一预警，在1973-1974年被完全验证。</p><h3 id="本土州保险-扩张与克制的平衡" tabindex="-1">本土州保险：扩张与克制的平衡 <a class="header-anchor" href="#本土州保险-扩张与克制的平衡" aria-label="Permalink to &quot;本土州保险：扩张与克制的平衡&quot;">​</a></h3><p>内布拉斯加意外保险公司（HomeState）：保费规模已达到当地老牌巨头约1/3，但综合成本率仍偏高。管理层坚持&quot;宁可不扩张，也要保持承保盈利&quot;的原则。</p><p><strong>这是在1972年，伯克希尔就已确立的&quot;本土州扩张标准&quot;</strong>——只允许在承保盈利的前提下扩张，而不是为了规模放弃纪律。</p><h3 id="纺织业务-复苏-但相对改善更重要" tabindex="-1">纺织业务：复苏，但相对改善更重要 <a class="header-anchor" href="#纺织业务-复苏-但相对改善更重要" aria-label="Permalink to &quot;纺织业务：复苏，但相对改善更重要&quot;">​</a></h3><p>1972年纺织行业复苏，Ken Chace 团队大幅改善了产品结构和库存管理。但巴菲特明确说：行业复苏是外部因素，公司的真正进步是<strong>相对行业地位的提升</strong>。</p><blockquote><p>&quot;公司在行业内的相对地位已明显提升，1973年前景向好。&quot;</p></blockquote><p>这是巴菲特一贯的思维方式：绝对业绩受环境影响，相对竞争力才是管理层的真正贡献。</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><p><strong>洞察一：股东权益回报率是终极指标</strong></p><p>1972年巴菲特首次在年报中明确：&quot;我始终认为，<strong>股东权益回报率</strong>才是衡量企业经营表现的恰当指标，而非每股收益或股价表现。&quot;这句话在后来50年几乎每封股东信都会重复。</p><p><strong>洞察二：三位创始人都留在原地</strong></p><p>Jack、Gene、Vic 三位创始人都是现金出售后继续全职经营。注意他们的共同点：</p><ol><li>都是在自己创办的公司里全职运营</li><li>都是真正的企业家，而非职业经理人</li><li>都从一开始就与巴菲特建立了高度信任</li></ol><p>这是伯克希尔&quot;人才收购&quot;模式的原型。</p><p><strong>洞察三：1964-1972年，股东权益增长3.5倍</strong></p><table tabindex="0"><thead><tr><th>指标</th><th>1964年末</th><th>1972年末</th></tr></thead><tbody><tr><td>股东权益</td><td>2213.9万美元</td><td>~6200万美元</td></tr><tr><td>流通股</td><td>1,137,778股</td><td>~980,000股</td></tr><tr><td>股价</td><td>$19.46 (账面)</td><td>$69.72 (账面)</td></tr><tr><td>年均复合增长</td><td>—</td><td><strong>16.8%</strong></td></tr></tbody></table><p>在不发新股、不举债的前提下，通过内生增长实现16.8%的年均复合增长。伯克希尔的复利机器已经启动。</p><h2 id="名言" tabindex="-1">名言 <a class="header-anchor" href="#名言" aria-label="Permalink to &quot;名言&quot;">​</a></h2><blockquote><p>&quot;1965年5月我们正式接手伯克希尔。八年后，营业收益达1111万美元，远高于若公司仍将全部资源投入纺织业务所能实现的收益。&quot; ——沃伦·巴菲特，1972年年报</p></blockquote><p>（解读：这是巴菲特第一次用数据证明&quot;资本重新配置&quot;的威力。如果当初不变，今天的营业收益可能只有零甚至负数。）</p><h2 id="历史坐标" tabindex="-1">历史坐标 <a class="header-anchor" href="#历史坐标" aria-label="Permalink to &quot;历史坐标&quot;">​</a></h2><ul><li>距离1956年巴菲特合伙基金：<strong>16年</strong></li><li>距离1965年接手伯克希尔：<strong>7年</strong></li><li>这是伯克希尔转型后的<strong>第一个历史性高峰</strong>，随后两年将遭遇严重挫折</li><li>距离1973-1974年保险危机：<strong>1-2年</strong></li></ul>',37)])])}const c=o(d,[["render",l]]);export{p as __pageData,c as default};
